void Bitmap_Holder.MouseDrop(int bitmapID,int left,int top,int right,int bottom)

{

   if(textMode)   return;

   int res;

   HotSpot_Holder.PointInHotSpot(bitmapID,left+((right-left)/2),top+((bottom-top)/2),&res);

   if(res)

   {

      totalRes++;

      if(totalRes<4)

         Sound_Holder.PlayDSound(2);

      else

         Sound_Holder.PlayDSound(4);

      Bitmap_Holder.ShowBitmap(bitmapID+4);

      Bitmap_Holder.HideBitmap(bitmapID);

      ppp[bitmapID]=1;



      int curP=Random(0,3);

      if(ppp[curP])

      {

         int ttt=0;

         while(ttt<4)

         {

            curP++;

            ttt++;

            if(curP>3)   curP=0;

            if(ppp[curP]==0)   

            {

               Bitmap_Holder.ShowBitmap(curP);

               break;

            }

         }

      }

      else

         Bitmap_Holder.ShowBitmap(curP);

   }

   else

   {

      Sound_Holder.PlayDSound(3);

      switch(bitmapID)

      {

         case 0:

            Bitmap_Holder.MoveTo(bitmapID,21,396);

            break;

         case 1:

            Bitmap_Holder.MoveTo(bitmapID,77,404);

            break;

         case 2:

            Bitmap_Holder.MoveTo(bitmapID,56,387);

            break;

         case 3:

            Bitmap_Holder.MoveTo(bitmapID,78,392);

            break;

      }

   }



}





